4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
19	      new Set(block.map((c) => c.join(","))),
20	    );
21	  });
22	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — L-shape [(0,0),(1,0),(0,1)] → block [(0,0),(1,0),(0,1),(1,1)]", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
25	      new Set(["0,0", "1,0", "0,1", "1,1"]),
26	    );
27	  });
28	  it("live cell with more than 3 neighbors dies from overpopulation — filled 3x3 center dies", () => {
